// 🤖 Initialize AI Outreach Orchestration - FIXED TO MATCH WORKING PATTERN
// This should receive the output from "🎯 Process AI Outreach Campaign Form Data"

const campaignData = $input.first().json;
const sessionId = campaignData.session_id || Math.random().toString(36).substr(2, 9);
const timestamp = new Date().toISOString();

// Extract campaign configuration from processed form data
const campaignConfig = campaignData.campaign_config || {};
const sendsparkConfig = campaignData.sendspark_config || { enabled: false };
const aiInstructions = campaignData.ai_instructions || {};
const airtableConfig = campaignData.airtable_config || {};

// Build enhanced orchestration context that matches the working workflow
const outreachContext = {
  // Session Management
  session_id: sessionId,
  campaign_name: campaignData.campaign_name || 'AI Outreach Campaign',
  workflow_start: timestamp,
  trigger_source: campaignData.trigger_source || 'wizard_form_submission',
  workflow_stage: 'orchestration_ready',

  // Campaign Configuration (from processed form)
  campaign_config: {
    batch_size: campaignConfig.batch_size || 1,
    campaign_focus: campaignConfig.campaign_focus || 'premium_prospects',
    campaign_type: sendsparkConfig.enabled ? 'video_enhanced' : 'email_only',
    video_enabled: sendsparkConfig.enabled || false,
    video_threshold: sendsparkConfig.video_threshold || 80,
    target_industry: campaignConfig.target_industry || null,
    priority_level: campaignConfig.priority_level || 'high',
    additional_instructions: campaignConfig.additional_instructions || '',

    // User Selection Context (from form processing)
    user_selections: campaignConfig.user_selections || {}
  },

  // SendSpark Configuration (from processed form)
  sendspark_config: sendsparkConfig,

  // AI Instructions (from processed form)
  ai_instructions: {
    primary_objective: aiInstructions.primary_objective || `Execute ${campaignData.campaign_name || 'Smart Outreach Campaign'} with ${sendsparkConfig.enabled ? 'video-enhanced' : 'email-only'} personalized outreach`,

    processing_strategy: aiInstructions.processing_strategy || {
      high_value_leads: sendsparkConfig.enabled ? 'Create SendSpark videos + premium emails' : 'Focus on premium email personalization',
      medium_value_leads: 'Standard personalized email outreach',
      lead_prioritization: campaignConfig.priority_level || 'high',
      industry_focus: campaignConfig.target_industry ? `Focus on ${campaignConfig.target_industry} industry prospects` : 'Cross-industry approach'
    },

    messaging_guidelines: aiInstructions.messaging_guidelines || {
      tone: campaignConfig.campaign_focus === 'quick_wins' ? 'Direct and action-oriented' : 'Professional and relationship-building',
      personalization_level: campaignConfig.campaign_focus === 'premium_prospects' ? 'Deep research-based' : 'Standard company-based',
      call_to_action: campaignConfig.campaign_focus === 'quick_wins' ? 'Meeting request' : 'Value-driven conversation starter',
      additional_context: campaignConfig.additional_instructions || 'Follow standard best practices'
    },

    success_metrics: aiInstructions.success_metrics || {
      target_response_rate: campaignConfig.campaign_focus === 'premium_prospects' ? '15-25%' : '12-20%',
      expected_meetings: Math.round((campaignConfig.batch_size || 1) * 0.15),
      video_creation_target: sendsparkConfig.enabled ? Math.round((campaignConfig.batch_size || 15) * 0.4) : 0
    }
  },

  // Airtable Configuration (from processed form)
  airtable_config: airtableConfig,

  // Orchestration Brief
  orchestration_brief: {
    objective: `Execute ${campaignData.campaign_name || 'Smart Outreach Campaign'} with ${sendsparkConfig.enabled ? 'video-enhanced' : 'email-only'} personalized outreach`,
    campaign_type: sendsparkConfig.enabled ? 'Premium Video Campaign' : 'Standard Email Campaign',
    batch_size: campaignConfig.batch_size || 1,
    target_industry: campaignConfig.target_industry || 'All Industries',

    available_specialists: [
      'Lead Intelligence Agent',
      'Personalization Strategist Agent',
      ...(sendsparkConfig.enabled ? ['SendSpark Video Creator Agent'] : []),
      'Email Optimization Agent',
      'Outreach Coordinator Agent',
      'Performance Analytics Agent'
    ],

    data_sources: ['Airtable Leads', 'Company Intelligence', 'Industry Analysis', 'Performance Metrics'],
    target_channels: [
      ...(sendsparkConfig.enabled ? ['SendSpark Video'] : []),
      'Gmail Email',
      'LinkedIn DM'
    ],
    outreach_types: [
      ...(sendsparkConfig.enabled ? ['VIDEO_ENHANCED'] : []),
      'PERSONALIZED_EMAIL',
      'MULTI_TOUCH_SEQUENCE'
    ]
  },

  // Lead Selection Criteria (from processed form)
  lead_criteria: {
    min_lead_score: 60,
    required_fields: ['Email', 'Company Name', 'Business Description'],
    email_status: 'verified',
    ready_for_sendspark: sendsparkConfig.enabled,
    ready_to_send: true,
    target_industry: campaignConfig.target_industry,
    batch_limit: campaignConfig.batch_size || 1
  },

  // Routing Decision
  routing_decision: {
    use_sendspark: sendsparkConfig.enabled || false,
    video_threshold: sendsparkConfig.video_threshold || 80,
    processing_mode: sendsparkConfig.enabled ? 'video_enhanced' : 'email_only'
  },

  // Workflow Routing
  next_steps: {
    fetch_leads: true,
    ai_processing: true,
    sendspark_integration: sendsparkConfig.enabled || false,
    email_drafting: true,
    progress_tracking: true
  }
};

console.log(`🤖 AI Outreach Orchestration Initialized - Session: ${sessionId}`);
console.log(`   🎯 Campaign: ${outreachContext.campaign_name}`);
console.log(`   📊 Configured Batch Size: ${campaignConfig.batch_size || 15}`);
console.log(`   🎯 Campaign Focus: ${campaignConfig.campaign_focus || 'premium_prospects'}`);
console.log(`   🎥 SendSpark: ${sendsparkConfig.enabled ? 'ENABLED' : 'DISABLED'}`);
console.log(`   🎯 Processing Mode: ${outreachContext.routing_decision.processing_mode}`);
console.log(`   🏭 Target Industry: ${campaignConfig.target_industry || 'All Industries'}`);

return [{ json: outreachContext }];

