// 🎯 Process AI Outreach Campaign Form Data - FIXED FOR ACTUAL DATA
const formData = $input.first().json;
const sessionId = Math.random().toString(36).substr(2, 9);
const timestamp = new Date().toISOString();

console.log('🚀 Processing Outreach Campaign Form:', formData);

// Extract form fields with emoji-enhanced field names
const campaignName = formData['🎯 Campaign Name'] || 'AI Outreach Campaign';

// Extract batch size from descriptive dropdown text
const batchSizeText = formData['📊 How many leads do you want to contact?'] || '';
let batchSize = 15;
if (batchSizeText.includes('1-5')) batchSize = 1;
else if (batchSizeText.includes('10-15')) batchSize = 15;
else if (batchSizeText.includes('20-30')) batchSize = 30;
else if (batchSizeText.includes('35-50')) batchSize = 50;
else if (batchSizeText.includes('60-75')) batchSize = 75;

// Extract campaign goal from dropdown
const campaignGoalText = formData['🎯 What\'s your primary campaign goal?'] || '';
let campaignFocus = 'premium_prospects';
let priorityLevel = 'high';
if (campaignGoalText.includes('Premium Prospects')) {
  campaignFocus = 'premium_prospects';
  priorityLevel = 'high';
} else if (campaignGoalText.includes('Quick Wins')) {
  campaignFocus = 'quick_wins';
  priorityLevel = 'urgent';
} else if (campaignGoalText.includes('Strategic Growth')) {
  campaignFocus = 'strategic_growth';
  priorityLevel = 'medium';
} else if (campaignGoalText.includes('Industry Specific')) {
  campaignFocus = 'industry_specific';
  priorityLevel = 'high';
}

// Extract SendSpark preference
const sendSparkText = formData['🎥 Include personalized SendSpark videos?'] || '';
const includeSendSpark = sendSparkText.includes('Yes');
const campaignType = includeSendSpark ? 'video_enhanced' : 'email_only';

// Extract video threshold from dropdown
const videoThresholdText = formData['⭐ Video creation threshold (lead score)'] || '';
let videoThreshold = 80;
if (videoThresholdText.includes('90+')) videoThreshold = 90;
else if (videoThresholdText.includes('80+')) videoThreshold = 80;
else if (videoThresholdText.includes('70+')) videoThreshold = 70;
else if (videoThresholdText.includes('60+')) videoThreshold = 60;

// Extract target industry
const targetIndustryText = formData['🏭 Target Industry (Optional)'] || '';
let targetIndustry = null;
let industryFilter = '';

if (targetIndustryText && !targetIndustryText.includes('All Industries')) {
  if (targetIndustryText.includes('Technology')) {
    targetIndustry = 'technology';
    industryFilter = 'OR(FIND("technology", LOWER({Company Industry})) > 0, FIND("software", LOWER({Company Industry})) > 0, FIND("saas", LOWER({Company Industry})) > 0, FIND("information technology", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('Healthcare')) {
    targetIndustry = 'healthcare';
    industryFilter = 'OR(FIND("healthcare", LOWER({Company Industry})) > 0, FIND("medical", LOWER({Company Industry})) > 0, FIND("pharmaceutical", LOWER({Company Industry})) > 0, FIND("biotechnology", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('Financial')) {
    targetIndustry = 'financial_services';
    industryFilter = 'OR(FIND("financial", LOWER({Company Industry})) > 0, FIND("banking", LOWER({Company Industry})) > 0, FIND("fintech", LOWER({Company Industry})) > 0, FIND("financial services", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('E-commerce')) {
    targetIndustry = 'ecommerce';
    industryFilter = 'OR(FIND("ecommerce", LOWER({Company Industry})) > 0, FIND("retail", LOWER({Company Industry})) > 0, FIND("e-commerce", LOWER({Company Industry})) > 0, FIND("consumer goods", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('Manufacturing')) {
    targetIndustry = 'manufacturing';
    industryFilter = 'OR(FIND("manufacturing", LOWER({Company Industry})) > 0, FIND("industrial", LOWER({Company Industry})) > 0, FIND("electrical", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('Education')) {
    targetIndustry = 'education';
    industryFilter = 'OR(FIND("education", LOWER({Company Industry})) > 0, FIND("learning", LOWER({Company Industry})) > 0, FIND("university", LOWER({Company Industry})) > 0, FIND("e-learning", LOWER({Company Industry})) > 0)';
  } else if (targetIndustryText.includes('Construction')) {
    targetIndustry = 'construction';
    industryFilter = 'OR(FIND("construction", LOWER({Company Industry})) > 0, FIND("real estate", LOWER({Company Industry})) > 0, FIND("building", LOWER({Company Industry})) > 0, FIND("architecture", LOWER({Company Industry})) > 0)';
  }
}

const additionalInstructions = formData['📝 Additional Campaign Instructions'] || '';

// SendSpark configuration with updated field names
const sendsparkConfig = includeSendSpark ? {
  enabled: true,
  workspace_id: formData['🏢 SendSpark Workspace ID'] || null,
  campaign_id: formData['📹 SendSpark Campaign ID'] || null,
  api_key: formData['🔑 SendSpark API Key'] || null,
  api_secret: formData['🔐 SendSpark API Secret'] || null,
  video_threshold: videoThreshold
} : {
  enabled: false
};

// Build Airtable filter - FIXED FOR ACTUAL DATA VALUES
// Based on CSV analysis: Processing Status = "ready_for_outreach", boolean fields use "checked"
let airtableFilter = 'AND({Processing Status} = "ready_for_outreach", {Email Status} = "verified", {Email Confidence} >= 75)';

// Add lead score filter if we have scores (many records have empty scores)
if (campaignFocus === 'premium_prospects') {
  airtableFilter = `AND(${airtableFilter.slice(4, -1)}, {Final Lead Score} >= 80)`;
} else {
  // For other campaigns, be more flexible with scoring
  airtableFilter = `AND(${airtableFilter.slice(4, -1)}, OR({Final Lead Score} >= 60, {Final Lead Score} = BLANK()))`;
}

// Add industry filter if specified
if (industryFilter) {
  airtableFilter = `AND(${airtableFilter.slice(4, -1)}, ${industryFilter})`;
}

// Add campaign focus specific filters
if (campaignFocus === 'quick_wins') {
  airtableFilter = `AND(${airtableFilter.slice(4, -1)}, {Email Confidence} >= 85, OR({Seniority Level} = "C-Level", {Seniority Level} = "VP"))`;
} else if (campaignFocus === 'strategic_growth') {
  airtableFilter = `AND(${airtableFilter.slice(4, -1)}, {Company Size} >= 20, OR({Funding Status} = "Series A", {Funding Status} = "Series B", {Funding Status} = "Private", {Funding Status} = "Seed"))`;
}

// Build comprehensive campaign context for AI agent
const campaignContext = {
  // Session Management
  session_id: sessionId,
  campaign_name: campaignName,
  workflow_start: timestamp,
  trigger_source: 'wizard_form_submission',
  workflow_stage: 'leads_selected',

  // Campaign Configuration
  campaign_config: {
    batch_size: batchSize,
    campaign_focus: campaignFocus,
    campaign_type: campaignType,
    video_enabled: includeSendSpark,
    video_threshold: videoThreshold,
    target_industry: targetIndustry,
    priority_level: priorityLevel,
    additional_instructions: additionalInstructions,

    // User Selection Context
    user_selections: {
      batch_selection: batchSizeText,
      goal_selection: campaignGoalText,
      video_selection: sendSparkText,
      threshold_selection: videoThresholdText,
      industry_selection: targetIndustryText
    }
  },

  // SendSpark Configuration
  sendspark_config: sendsparkConfig,

  // AI Agent Instructions
  ai_instructions: {
    primary_objective: `Execute ${campaignName} targeting ${batchSize} ${campaignFocus.replace('_', ' ')} leads with ${includeSendSpark ? 'video-enhanced' : 'email-only'} personalized outreach`,

    processing_strategy: {
      high_value_leads: includeSendSpark ? `Create SendSpark videos for leads with score >= ${videoThreshold}` : 'Focus on premium email personalization',
      medium_value_leads: 'Standard personalized email outreach',
      lead_prioritization: `Prioritize ${priorityLevel} priority leads based on ${campaignFocus} strategy`,
      industry_focus: targetIndustry ? `Focus on ${targetIndustry} industry prospects` : 'Cross-industry approach'
    },

    messaging_guidelines: {
      tone: campaignFocus === 'quick_wins' ? 'Direct and action-oriented' : 'Professional and relationship-building',
      personalization_level: campaignFocus === 'premium_prospects' ? 'Deep research-based' : 'Standard company-based',
      call_to_action: campaignFocus === 'quick_wins' ? 'Meeting request' : 'Value-driven conversation starter',
      additional_context: additionalInstructions || 'Follow standard best practices'
    },

    success_metrics: {
      target_response_rate: campaignFocus === 'premium_prospects' ? '15-25%' : campaignFocus === 'quick_wins' ? '20-35%' : '12-20%',
      expected_meetings: Math.round(batchSize * 0.15),
      video_creation_target: includeSendSpark ? Math.round(batchSize * 0.4) : 0
    }
  },

  // Airtable Query Configuration - FIXED FOR ACTUAL DATA
  airtable_config: {
    filter_formula: airtableFilter,
    sort_by: 'Final Lead Score',  // Changed from Final Lead Score since many are empty
    sort_direction: 'desc',
    limit: batchSize * 3, // Increased limit since filtering is stricter
    required_fields: [
      'Record ID', 'Full Name', 'Email', 'Job Title', 'Company Name', 'Company Industry', 
      'Final Lead Score', 'Email Confidence', 'Seniority Level', 
      'Company Size', 'Funding Status', 'Personal LinkedIn URL', 'Email Status',
      'Processing Status', 'Company Website',  'Business Description', 'Service Offering', 'Target Industry'
    ]
  },

  // Workflow Routing
  next_steps: {
    fetch_leads: true,
    ai_processing: true,
    sendspark_integration: includeSendSpark,
    email_drafting: true,
    progress_tracking: true
  }
};

// Validate SendSpark configuration if enabled
if (includeSendSpark) {
  const missingFields = [];
  if (!sendsparkConfig.workspace_id) missingFields.push('Workspace ID');
  if (!sendsparkConfig.campaign_id) missingFields.push('Campaign ID');
  if (!sendsparkConfig.api_key) missingFields.push('API Key');
  if (!sendsparkConfig.api_secret) missingFields.push('API Secret');

  if (missingFields.length > 0) {
    campaignContext.validation_warnings = [`SendSpark enabled but missing: ${missingFields.join(', ')}`];
    console.warn(`⚠️ SendSpark validation warning: Missing ${missingFields.join(', ')}`);
  }
}

// Enhanced logging
console.log(`🎯 Campaign Configured: ${campaignName}`);
console.log(`   📊 Batch Size: ${batchSize} (${batchSizeText.split(' - ')[1] || 'Custom'})`);
console.log(`   🎯 Focus: ${campaignFocus} (${priorityLevel} priority)`);
console.log(`   🎥 SendSpark: ${includeSendSpark ? 'Premium Video Mode' : 'Standard Email Mode'}`);
console.log(`   📈 Video Threshold: ${videoThreshold}`);
console.log(`   🏭 Industry: ${targetIndustry || 'All Industries'}`);
console.log(`   🔍 Airtable Filter: ${airtableFilter}`);

// Return the processed campaign context
return [{ json: campaignContext }];

// 📊 Campaign Summary Generator
const allResults = $input.all();
const sessionId = allResults[0]?.json?.session_id || 'Unknown';
const campaignName = allResults[0]?.json?.campaign_name || 'AI Outreach Campaign';

// Aggregate results
const totalLeads = allResults.length;
const successfulDrafts = allResults.filter(item => 
  item.json && (item.json.gmail_draft_created || item.json.subject)
).length;

const companies = allResults.map(item => {
  const leadData = item.json?.lead || item.json;
  return {
    name: leadData?.['Full Name'] || 'Unknown',
    company: leadData?.['Company Name'] || 'Unknown Company',
    industry: leadData?.['Company Industry'] || 'Unknown',
    score: leadData?.['Final Lead Score'] || 0
  };
});

// Calculate stats
const avgScore = Math.round(companies.reduce((sum, lead) => sum + lead.score, 0) / companies.length);
const industries = [...new Set(companies.map(c => c.industry))];
const topCompanies = companies.slice(0, 5); // Top 5 for summary

// Create comprehensive summary
const summary = `🚀 **OUTREACH CAMPAIGN COMPLETED**

📊 **Campaign Overview:**
• Campaign: ${campaignName}
• Session: ${sessionId}
• Total Leads Processed: ${totalLeads}
• Gmail Drafts Created: ${successfulDrafts}
• Success Rate: ${Math.round((successfulDrafts/totalLeads)*100)}%

📈 **Lead Quality:**
• Average Lead Score: ${avgScore}/100
• Industries: ${industries.slice(0,3).join(', ')}${industries.length > 3 ? ` +${industries.length-3} more` : ''}

👥 **Top Prospects:**
${topCompanies.map(lead => 
  `• ${lead.name} - ${lead.company} (${lead.score})`
).join('\n')}

✅ **Actions Completed:**
• ${successfulDrafts} Gmail drafts ready for review
• ${successfulDrafts} Airtable records updated
• All leads marked as processed

🎯 **Next Steps:**
Review Gmail drafts and begin sending personalized outreach emails.

Campaign completed at ${new Date().toLocaleString()}`;

return [{ json: { telegram_summary: summary } }];

// 🎯 Prepare AI Context - UPDATED FOR SENDSPARK VIDEO INTEGRATION
const allInputs = $input.all();
console.log(`📥 Received ${allInputs.length} inputs from workflow`);

// Determine data sources based on workflow routing
let campaignContext, leadData, sendsparkVideos = [];

// Check if we have SendSpark video data (from video creation branch)
const hasSendSparkData = allInputs.some(input => 
  input.json && (input.json.shareUrl || input.json.prospectList || input.json.contactEmail)
);

if (hasSendSparkData) {
  // Video-enhanced workflow: Campaign Context + Lead Data + SendSpark Videos
  campaignContext = allInputs.find(input => input.json && input.json.session_id)?.json;

  // Handle SendSpark API response format
  sendsparkVideos = allInputs.filter(input => {
    return input.json && (
      input.json.prospectList || // Standard API response
      input.json.shareUrl || // Direct video object
      (input.json.contactEmail && input.json.status) // Individual prospect
    );
  }).map(input => {
    // Normalize different SendSpark response formats
    if (input.json.prospectList && input.json.prospectList.length > 0) {
      return input.json.prospectList[0]; // Extract first prospect from list
    } else if (input.json.shareUrl || input.json.contactEmail) {
      return input.json; // Already in correct format
    }
    return null;
  }).filter(video => video !== null);

  leadData = allInputs.filter(input => 
    input.json && input.json.id && input.json['Full Name'] && !input.json.shareUrl && !input.json.prospectList
  ).map(input => input.json);
} else {
  // Email-only workflow: Campaign Context + Lead Data
  campaignContext = allInputs.find(input => input.json && input.json.session_id)?.json;
  leadData = allInputs.filter(input => 
    input.json && input.json.id && input.json['Full Name']
  ).map(input => input.json);
}

// Fallback if campaign context is not found in expected format
if (!campaignContext) {
  campaignContext = allInputs[0]?.json || {};
}

console.log(`🎯 Data Analysis:`);
console.log(`   📊 Campaign Context: ${campaignContext.campaign_name || 'Found'}`);
console.log(`   🗃️ Lead Records: ${leadData.length}`);
console.log(`   🎥 SendSpark Videos: ${sendsparkVideos.length}`);

// Create SendSpark video lookup map for easy integration - UPDATED FOR API RESPONSE
const videoLookup = {};
sendsparkVideos.forEach(video => {
  if (video && video.contactEmail) {
    videoLookup[video.contactEmail] = {
      videoUrl: video.shareUrl,
      videoId: video._id || video.id,
      createdAt: video.createdAt || new Date().toISOString(),
      status: video.status || 'created',
      valid: video.valid || false,
      screenshotUrl: video.screenshotUrl || null
    };
  }
});

// Enhance lead data with SendSpark video information
const enhancedLeads = leadData.map(lead => {
  const leadEmail = lead.Email;
  const hasVideo = videoLookup[leadEmail];

  return {
    ...lead,
    // Add SendSpark integration data - UPDATED FORMAT
    sendspark_integration: hasVideo ? {
      video_created: true,
      video_url: hasVideo.videoUrl,
      video_id: hasVideo.videoId,
      video_status: hasVideo.status,
      video_valid: hasVideo.valid,
      screenshot_url: hasVideo.screenshotUrl,
      created_at: hasVideo.createdAt
    } : {
      video_created: false,
      video_eligible: (lead['Final Lead Score'] || 0) >= (campaignContext.sendspark_config?.video_threshold || 80),
      video_url: null,
      video_id: null,
      video_status: null,
      screenshot_url: null
    },

    // Add processing tier classification
    processing_tier: (() => {
      const score = lead['Final Lead Score'] || 0;
      const videoThreshold = campaignContext.sendspark_config?.video_threshold || 80;

      if (score >= videoThreshold) return 'high_value';
      if (score >= 65) return 'medium_value';
      if (score >= 60) return 'qualified';
      return 'basic';
    })()
  };
});

// Sort leads by processing tier priority (high_value first)
const sortedLeads = enhancedLeads.sort((a, b) => {
  const tierPriority = { 'high_value': 3, 'medium_value': 2, 'qualified': 1, 'basic': 0 };
  const aPriority = tierPriority[a.processing_tier] || 0;
  const bPriority = tierPriority[b.processing_tier] || 0;

  // Sort by tier priority first, then by lead score
  if (aPriority !== bPriority) {
    return bPriority - aPriority; // Higher priority first
  }
  return (b['Final Lead Score'] || 0) - (a['Final Lead Score'] || 0); // Higher score first
});

// Calculate processing statistics for campaign context
const processingStats = {
  total_leads: enhancedLeads.length,
  high_value_leads: enhancedLeads.filter(lead => lead.processing_tier === 'high_value').length,
  medium_value_leads: enhancedLeads.filter(lead => lead.processing_tier === 'medium_value').length,
  qualified_leads: enhancedLeads.filter(lead => lead.processing_tier === 'qualified').length,
  basic_leads: enhancedLeads.filter(lead => lead.processing_tier === 'basic').length,

  // SendSpark Statistics - UPDATED
  videos_created: sendsparkVideos.length,
  videos_successful: sendsparkVideos.filter(v => v.valid && v.status === 'completed').length,
  videos_processing: sendsparkVideos.filter(v => v.status === 'processing').length,
  videos_pending: enhancedLeads.filter(lead => 
    lead.sendspark_integration.video_eligible && !lead.sendspark_integration.video_created
  ).length,
  video_eligible_count: enhancedLeads.filter(lead => lead.sendspark_integration.video_eligible).length,

  // Quality Metrics
  avg_lead_score: Math.round(enhancedLeads.reduce((sum, lead) => sum + (lead['Final Lead Score'] || 0), 0) / enhancedLeads.length),
  avg_email_confidence: Math.round(enhancedLeads.reduce((sum, lead) => sum + (lead['Email Confidence'] || 0), 0) / enhancedLeads.length),
  c_level_count: enhancedLeads.filter(lead => lead['Seniority Level'] === 'C-Level').length,
  verified_emails: enhancedLeads.filter(lead => lead['Email Status'] === 'verified').length
};

// Build shared campaign context (will be included with each lead)
const sharedCampaignContext = {
  // Session Management
  session_id: campaignContext.session_id || Math.random().toString(36).substr(2, 9),
  campaign_name: campaignContext.campaign_name || 'AI Outreach Campaign',
  workflow_stage: 'ai_processing_ready',
  processing_timestamp: new Date().toISOString(),

  // Campaign Configuration
  campaign_config: campaignContext.campaign_config || {},
  sendspark_config: campaignContext.sendspark_config || { enabled: false },
  ai_instructions: campaignContext.ai_instructions || {},
  routing_decision: campaignContext.routing_decision || { processing_mode: 'email_only' },

  // Processing Statistics (campaign overview)
  processing_brief: processingStats,

  // SendSpark Integration Status - UPDATED
  sendspark_status: {
    enabled: campaignContext.sendspark_config?.enabled || false,
    videos_available: sendsparkVideos.length > 0,
    video_integration_complete: sendsparkVideos.length > 0,
    video_threshold: campaignContext.sendspark_config?.video_threshold || 80,
    workspace_id: campaignContext.sendspark_config?.workspace_id,
    campaign_id: campaignContext.sendspark_config?.campaign_id,
    videos_successful: processingStats.videos_successful,
    videos_processing: processingStats.videos_processing
  },

  // AI Processing Instructions - UPDATED FOR VIDEO INTEGRATION
  processing_instructions: {
    high_value_strategy: campaignContext.sendspark_config?.enabled 
      ? (sendsparkVideos.length > 0 
        ? 'Integrate existing SendSpark videos into premium email campaigns'
        : 'Create SendSpark videos AND premium emails for high-value leads')
      : 'Focus on premium email personalization for high-value leads',

    medium_value_strategy: 'Standard personalized email outreach with company-specific insights',
    qualified_strategy: 'Efficient template-based personalization with key company details',

    video_integration_mode: sendsparkVideos.length > 0 ? 'use_existing_videos' : 
      (campaignContext.sendspark_config?.enabled ? 'create_new_videos' : 'email_only'),

    video_email_template: campaignContext.sendspark_config?.enabled ? {
      subject_pattern: '[First Name], quick personalized video for [Company]',
      opening_line: 'I created a quick personalized video for you about [specific value proposition]',
      video_placement: 'After opening line, before main value proposition',
      call_to_action: 'Worth a quick 15-minute conversation to explore this further?'
    } : null
  },

  // Tool Configuration
  tool_config: {
    airtable_base: 'appM31OKQZtVVzbS8',
    airtable_table: 'tblXRRZ1vHPbevxQT',
    sendspark_workspace: campaignContext.sendspark_config?.workspace_id,
    sendspark_campaign: campaignContext.sendspark_config?.campaign_id,
    gmail_integration: true,
    video_email_integration: sendsparkVideos.length > 0
  },

  // Success Metrics
  success_targets: {
    target_response_rate: campaignContext.ai_instructions?.success_metrics?.target_response_rate || '15-25%',
    expected_meetings: campaignContext.ai_instructions?.success_metrics?.expected_meetings || Math.round(enhancedLeads.length * 0.15),
    video_creation_target: campaignContext.ai_instructions?.success_metrics?.video_creation_target || 0,
    personalization_quality: campaignContext.ai_instructions?.messaging_guidelines?.personalization_level || 'high'
  }
};

// Enhanced Logging
console.log(`✅ AI Context Prepared - Individual Lead Processing:`);
console.log(`   🎯 Campaign: ${sharedCampaignContext.campaign_name}`);
console.log(`   📊 Total Leads: ${sortedLeads.length}`);
console.log(`   🔥 High-Value (${processingStats.high_value_leads}), ⚡ Medium (${processingStats.medium_value_leads}), 📈 Qualified (${processingStats.qualified_leads})`);
console.log(`   🎥 SendSpark Status: ${sharedCampaignContext.sendspark_status.enabled ? 'ENABLED' : 'DISABLED'}`);
console.log(`   🎬 Videos Created: ${processingStats.videos_created} (${processingStats.videos_successful} successful)`);
console.log(`   📧 Processing Mode: ${sharedCampaignContext.routing_decision.processing_mode}`);
console.log(`   🚀 Outputting ${sortedLeads.length} individual lead items for AI processing`);

// Validation warnings
if (sharedCampaignContext.sendspark_config.enabled && sendsparkVideos.length === 0 && processingStats.high_value_leads > 0) {
  console.warn(`⚠️ SendSpark enabled but no videos found for ${processingStats.high_value_leads} high-value leads`);
}

if (sortedLeads.length === 0) {
  console.warn(`⚠️ No leads found for processing - check Airtable filters`);
}

// 🎯 CRITICAL CHANGE: Return individual items for each lead
// Each item contains the lead data + shared campaign context
const outputItems = sortedLeads.map((lead, index) => {
  return {
    json: {
      // Individual Lead Data (primary focus for AI agent)
      lead: lead,
      lead_index: index + 1,
      total_leads: sortedLeads.length,

      // Shared Campaign Context (for reference and tool usage)
      ...sharedCampaignContext,

      // Processing Context for this specific lead
      current_lead_context: {
        processing_tier: lead.processing_tier,
        lead_score: lead['Final Lead Score'] || 0,
        email_confidence: lead['Email Confidence'] || 0,
        seniority_level: lead['Seniority Level'],
        company_size: lead['Company Size'],
        industry: lead['Company Industry'],
        sendspark_eligible: lead.sendspark_integration.video_eligible,
        sendspark_video_available: lead.sendspark_integration.video_created,
        sendspark_video_valid: lead.sendspark_integration.video_valid,

        // Processing recommendations for this lead
        recommended_approach: lead.processing_tier === 'high_value' ? 'premium_personalization' :
                             lead.processing_tier === 'medium_value' ? 'standard_personalization' : 'efficient_personalization',

        technical_detail_level: lead['Seniority Level'] === 'C-Level' ? 'business_focused' : 
                               lead['Seniority Level'] === 'VP' ? 'strategic_focused' : 'technical_focused'
      }
    }
  };
});

console.log(`🎯 Generated ${outputItems.length} individual lead items for AI agent processing`);
console.log(`   📋 Lead processing order: ${sortedLeads.map(l => `${l['Full Name']} (${l.processing_tier})`).join(', ')}`);

// Return array of individual lead items
return outputItems;

